sys_script_include.script:
var Logger = Class.create();
Logger.prototype = {
  initialize: function (source) {
    this._source = source || '';
  },

  error: function (message) {
    this._log('error', message, arguments);
  },

  warn: function (message) {
    this._log('warn', message, arguments);
  },

  info: function (message) {
    this._log('info', message, arguments);
  },

  debug: function (message) {
    this._log('debug', message, arguments);
  },

  _log: function (level, message, args) {
    var user = gs.getUser();
    var userId = user ? user.getID() : 'unknown';
    var timestamp = new GlideDateTime().getValue();
    var logMessage = timestamp + ' - User: ' + userId + ' - ' + this._source + ' - ' + message;

    args = Array.prototype.slice.call(args, 1); // Remove the message parameter from the arguments
    args.unshift(logMessage); // Add the logMessage as the first argument

    switch (level) {
      case 'error':
        gs.error.apply(gs, args);
        break;
      case 'warn':
        gs.warn.apply(gs, args);
        break;
      case 'info':
        gs.info.apply(gs, args);
        break;
      case 'debug':
        gs.debug.apply(gs, args);
        break;
      default:
        gs.debug.apply(gs, args);
    }
  },

  type: 'Logger',
};
